@Builder
@NoArgsConstructor
@AllArgsConstructor
@Entity
@Table(name = "users")
public class User {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false, unique = true)
    private String email;

    /**
     * BCrypt-hashed password.
     */
    @Column(nullable = false)
    private String password;

    private String firstName;

    private String lastName;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    private UserRole role;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "school_id")
    private School school;

package com.omnischool.entity;

import com.omnischool.enums.UserRole;
import jakarta.persistence.*;
import lombok.*;

import java.time.LocalDateTime;

/**
 * Platform user.
 */
@Getter
@Setter
@Builder
@NoArgsConstructor
@AllArgsConstructor
@Entity
@Table(name = "users")
public class User {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false, unique = true)
    private String email;

    /**
     * BCrypt-hashed password.
     */
    @Column(nullable = false)
    private String password;

    private String firstName;

    private String lastName;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    private UserRole role;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "school_id")
    private School school;

    @Builder.Default
    @Column(nullable = false)
    private Boolean isActive = true;

    @Column(nullable = false, updatable = false)
    private LocalDateTime createdAt;

    private LocalDateTime lastLogin;

    @PrePersist
    void onCreate() {
        this.createdAt = LocalDateTime.now();
        if (isActive == null) isActive = true;
    }
}

package com.omnischool.enums;

/**
 * Contact message handling status.
 */
public enum ContactMessageStatus {
    NEW,
    READ,
    REPLIED,
    ARCHIVED
}

package com.omnischool.enums;

/**
 * Demo request lifecycle status.
 *
 * Kept minimal to match the admin analytics workflow.
 */
public enum DemoStatus {
    /** En attente */
    PENDING,

    /** Non répondu */
    NO_RESPONSE,

    /** Démo planifiée */
    SCHEDULED
}

package com.omnischool.enums;

/**
 * Education level used in demo request.
 */
public enum EducationLevel {
    PRIMAIRE,
    COLLEGE,
    LYCEE,
    MIXTE
}

package com.omnischool.enums;

/**
 * Subscription plan.
 */
public enum SchoolPlan {
    FREE,
    BASIC,
    PREMIUM,
    ENTERPRISE
}

package com.omnischool.enums;

/**
 * School type.
 */
public enum SchoolType {
    PRIMARY,
    SECONDARY,
    BOTH
}

package com.omnischool.exception;

/**
 * Thrown when a requested resource does not exist.
 */
public class ResourceNotFoundException extends RuntimeException {
    public ResourceNotFoundException(String message) {
        super(message);
    }
}

package com.omnischool.repository;

import com.omnischool.entity.ContactMessage;
import com.omnischool.enums.ContactMessageStatus;
import org.springframework.data.jpa.repository.JpaRepository;

import java.time.LocalDateTime;

public interface ContactMessageRepository extends JpaRepository<ContactMessage, Long> {
    long countByStatus(ContactMessageStatus status);

    long countByCreatedAtBetween(LocalDateTime start, LocalDateTime end);
}

