}

.os-cardCta {
	width: 100%;
	height: 44px;
	border-radius: 8px;
	font-size: 14px;
	font-weight: 600;
	background: #2d472c;
	color: #fff;
	display: inline-flex;
	align-items: center;
	justify-content: center;
	gap: 8px;
	transition: opacity 0.2s ease;
}

.os-cardCta:hover {
	opacity: 0.9;
}

