    { src: dash2, alt: t('assistantDashboard.shots.1') },
    { src: dash3, alt: t('assistantDashboard.shots.2') },
    { src: dash4, alt: t('assistantDashboard.shots.3') },
    { src: dash5, alt: t('assistantDashboard.shots.4') },
