      <section style={{ backgroundColor: '#F9F9F7', paddingTop: '80px', paddingBottom: '80px' }}>
        <div className="max-w-[1280px] mx-auto px-6">
          <div className="grid lg:grid-cols-[55%_45%] gap-12">
            {/* Left - Contact Form */}
            <motion.div
