                        <div>
                          <label
                            style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }}
                            htmlFor="phone"
                          >
                            {t('contact.page.form.phone.label')}
                          </label>
                          <input
                            type="tel"
                            id="phone"
                            name="phone"
                            required
                            value={formData.phone}
                            onChange={handleInputChange}
                            placeholder={t('contact.page.form.phone.placeholder')}
                            style={{
                              width: '100%',
                              height: '40px',
                              border: '1px solid #E5E7EB',
                              borderRadius: '4px',
                              padding: '0 12px',
                              fontSize: '14px',
                              color: '#333333',
                              fontFamily: 'Inter, sans-serif',
                            }}
                            onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                            onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                          />
                        </div>
                      </div>

                      {/* Row 3 - Subject */}
                      <div style={{ marginBottom: '16px' }}>
                        <label
                          style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }}
                          htmlFor="subject"
                        >
                          {t('contact.page.form.subject.label')}
                        </label>
                        <select
                          id="subject"
                          name="subject"
                          required
                          value={formData.subject}
                          onChange={handleInputChange}
                          style={{
                            width: '100%',
                            height: '40px',
                            border: '1px solid #E5E7EB',
                            borderRadius: '4px',
                            padding: '0 12px',
                            fontSize: '14px',
                            color: '#333333',
                            fontFamily: 'Inter, sans-serif',
                            backgroundColor: 'white',
                          }}
                          onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                          onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                        >
                          <option value="">{t('contact.page.form.subject.placeholder')}</option>
                          <option value="demo">{t('contact.page.form.subject.options.demo')}</option>
                          <option value="features">{t('contact.page.form.subject.options.features')}</option>
                          <option value="pricing">{t('contact.page.form.subject.options.pricing')}</option>
                          <option value="support">{t('contact.page.form.subject.options.support')}</option>
                          <option value="partnership">{t('contact.page.form.subject.options.partnership')}</option>
                          <option value="other">{t('contact.page.form.subject.options.other')}</option>
                        </select>
                      </div>

                      {/* Row 4 - Message */}
                      <div style={{ marginBottom: '24px' }}>
                        <label
                          style={{ display: 'block', fontSize: '13px', color: '#6B7280', marginBottom: '8px' }}
                          htmlFor="message"
                        >
                          {t('contact.page.form.message.label')}
                        </label>
                        <textarea
                          id="message"
                          name="message"
                          required
                          value={formData.message}
                          onChange={handleInputChange}
                          placeholder={t('contact.page.form.message.placeholder')}
                          rows={5}
                          style={{
                            width: '100%',
                            border: '1px solid #E5E7EB',
                            borderRadius: '4px',
                            padding: '12px',
                            fontSize: '14px',
                            color: '#333333',
                            fontFamily: 'Inter, sans-serif',
                            resize: 'vertical',
                            minHeight: '120px',
                          }}
                          onFocus={(e) => (e.target.style.borderColor = '#2D472C')}
                          onBlur={(e) => (e.target.style.borderColor = '#E5E7EB')}
                        />
                      </div>

                      {/* Submit Button */}
                      {submitError && (
                        <div
                          role="alert"
                          style={{
                            marginBottom: '12px',
                            padding: '10px 12px',
                            borderRadius: '6px',
                            border: '1px solid rgba(239, 68, 68, 0.35)',
                            backgroundColor: 'rgba(239, 68, 68, 0.08)',
                            color: '#991B1B',
                            fontSize: '13px',
                          }}
                        >
                          {submitError}
                        </div>
                      )}

                      <button
                        type="submit"
                        disabled={isSubmitting}
                        style={{
                          width: '100%',
                          height: '48px',
                          backgroundColor: '#2D472C',
                          color: 'white',
                          fontFamily: 'Inter, sans-serif',
                          fontSize: '15px',
                          fontWeight: '600',
                          borderRadius: '4px',
                          border: 'none',
                          cursor: isSubmitting ? 'not-allowed' : 'pointer',
                          transition: 'all 0.2s ease-out',
                          opacity: isSubmitting ? 0.85 : 1,
                        }}
                        onMouseEnter={(e) => {
                          if (!isSubmitting) e.currentTarget.style.opacity = '0.9';
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.opacity = isSubmitting ? '0.85' : '1';
                        }}
                      >
                        {isSubmitting ? t('contact.page.form.submitting') : t('contact.page.form.submit')}
                      </button>
                    </form>
                  </>
                ) : (
                  /* Success State */
                  <div style={{ textAlign: 'center', padding: '40px 0' }}>
                    <CheckCircle size={64} style={{ color: '#C5A059', margin: '0 auto 24px' }} />
                    <h2
                      style={{
                        fontFamily: 'Montserrat, sans-serif',
                        fontSize: '24px',
                        fontWeight: '700',
                        color: '#333333',
                        marginBottom: '12px',
                      }}
                    >
                      {t('contact.page.success.title')}
                    </h2>
                    <p style={{ fontSize: '15px', color: '#6B7280', marginBottom: '32px' }}>
                      {t('contact.page.success.subtitle')}
                    </p>
                    <Link to="/">
                      <button
                        style={{
                          padding: '12px 32px',
                          backgroundColor: 'white',
                          color: '#2D472C',
                          border: '1px solid #2D472C',
                          borderRadius: '4px',
                          fontSize: '15px',
                          fontWeight: '600',
                          cursor: 'pointer',
                          transition: 'all 0.2s ease-out',
                        }}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.backgroundColor = '#2D472C';
                          e.currentTarget.style.color = 'white';
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.backgroundColor = 'white';
                          e.currentTarget.style.color = '#2D472C';
                        }}
                      >
                        {t('contact.page.success.backHome')}
                      </button>
                    </Link>
                  </div>
                )}
              </div>
            </motion.div>

            {/* Right - Contact Info */}
            <motion.div
              initial={{ opacity: 0, x: 20 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.6, ease: 'easeOut' }}
            >
              <h2
                style={{
                  fontFamily: 'Montserrat, sans-serif',
                  fontSize: '22px',
                  fontWeight: '600',
                  color: '#333333',
                  marginBottom: '24px',
                }}
              >
                {t('contact.page.info.title')}
              </h2>

              {/* Contact Info Rows */}
              <div style={{ display: 'flex', flexDirection: 'column', gap: '24px', marginBottom: '32px' }}>
                {/* Address */}
                <div>
                  <div style={{ display: 'flex', alignItems: 'flex-start', gap: '12px' }}>
                    <MapPin size={20} style={{ color: '#2D472C', marginTop: '2px', flexShrink: 0 }} />
                    <div>
                      <div
                        style={{
                          fontFamily: 'Inter, sans-serif',
                          fontSize: '14px',
                          fontWeight: '600',
                          color: '#333333',
                          marginBottom: '4px',
                        }}
                      >
                        {t('contact.page.info.addressLabel')}
                      </div>
                      <div style={{ fontSize: '14px', color: '#6B7280' }}>{t('contact.page.info.addressValue')}</div>
                    </div>
                  </div>
                </div>

                {/* Email */}
                <div>
                  <div style={{ display: 'flex', alignItems: 'flex-start', gap: '12px' }}>
                    <Mail size={20} style={{ color: '#2D472C', marginTop: '2px', flexShrink: 0 }} />
                    <div>
                      <div
                        style={{
                          fontFamily: 'Inter, sans-serif',
                          fontSize: '14px',
                          fontWeight: '600',
                          color: '#333333',
                          marginBottom: '4px',
                        }}
                      >
                        {t('contact.page.info.emailLabel')}
                      </div>
                      <div style={{ fontSize: '14px', color: '#6B7280' }}>contact@omnischool.tn</div>
                    </div>
                  </div>
                </div>

                {/* Phone */}
                <div>
                  <div style={{ display: 'flex', alignItems: 'flex-start', gap: '12px' }}>
                    <Phone size={20} style={{ color: '#2D472C', marginTop: '2px', flexShrink: 0 }} />
                    <div>
                      <div
                        style={{
                          fontFamily: 'Inter, sans-serif',
                          fontSize: '14px',
                          fontWeight: '600',
                          color: '#333333',
                          marginBottom: '4px',
                        }}
                      >
                        {t('contact.page.info.phoneLabel')}
                      </div>
                      <div style={{ fontSize: '14px', color: '#6B7280' }}>+216 XX XXX XXX</div>
                    </div>
                  </div>
                </div>

                {/* Hours */}
                <div>
                  <div style={{ display: 'flex', alignItems: 'flex-start', gap: '12px' }}>
                    <Clock size={20} style={{ color: '#2D472C', marginTop: '2px', flexShrink: 0 }} />
                    <div>
                      <div
                        style={{
                          fontFamily: 'Inter, sans-serif',
                          fontSize: '14px',
                          fontWeight: '600',
                          color: '#333333',
                          marginBottom: '4px',
                        }}
                      >
                        {t('contact.page.info.hoursLabel')}
                      </div>
                      <div style={{ fontSize: '14px', color: '#6B7280' }}>{t('contact.page.info.hoursValue')}</div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Social Links */}
              <div style={{ display: 'flex', gap: '12px' }}>
                <button
                  className="transition-all duration-200"
                  style={{
                    width: '40px',
                    height: '40px',
                    border: '1px solid #2D472C',
                    borderRadius: '8px',
                    backgroundColor: 'white',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    cursor: 'pointer',
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = '#2D472C';
                    const icon = e.currentTarget.querySelector('svg');
                    if (icon) (icon as SVGElement).style.color = 'white';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = 'white';
                    const icon = e.currentTarget.querySelector('svg');
                    if (icon) (icon as SVGElement).style.color = '#2D472C';
                  }}
                >
                  <Linkedin size={18} style={{ color: '#2D472C', transition: 'color 0.2s ease-out' }} />
                </button>
                <button
                  className="transition-all duration-200"
                  style={{
                    width: '40px',
                    height: '40px',
                    border: '1px solid #2D472C',
                    borderRadius: '8px',
                    backgroundColor: 'white',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    cursor: 'pointer',
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = '#2D472C';
                    const icon = e.currentTarget.querySelector('svg');
                    if (icon) (icon as SVGElement).style.color = 'white';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = 'white';
                    const icon = e.currentTarget.querySelector('svg');
                    if (icon) (icon as SVGElement).style.color = '#2D472C';
                  }}
                >
                  <Facebook size={18} style={{ color: '#2D472C', transition: 'color 0.2s ease-out' }} />
                </button>
                <button
                  className="transition-all duration-200"
                  style={{
                    width: '40px',
                    height: '40px',
                    border: '1px solid #2D472C',
                    borderRadius: '8px',
                    backgroundColor: 'white',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    cursor: 'pointer',
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = '#2D472C';
                    const icon = e.currentTarget.querySelector('svg');
                    if (icon) (icon as SVGElement).style.color = 'white';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = 'white';
                    const icon = e.currentTarget.querySelector('svg');
                    if (icon) (icon as SVGElement).style.color = '#2D472C';
                  }}
                >
                  <Instagram size={18} style={{ color: '#2D472C', transition: 'color 0.2s ease-out' }} />
                </button>
              </div>
            </motion.div>
          </div>
        </div>
      </section>

      {/* Section 4 - Google Map */}
      <section style={{ backgroundColor: 'white', paddingBottom: '0' }}>
        <div style={{ paddingTop: '40px', textAlign: 'center' }}>
          <h2
            style={{
              fontFamily: 'Montserrat, sans-serif',
              fontSize: '24px',
              fontWeight: '600',
              color: '#333333',
              marginBottom: '8px',
            }}
          >
            {t('contact.page.map.title')}
          </h2>
          <p style={{ fontSize: '14px', color: '#6B7280', marginBottom: '24px' }}>{t('contact.page.map.subtitle')}</p>
        </div>
        <div style={{ borderTop: '1px solid #E5E7EB', borderBottom: '1px solid #E5E7EB' }}>
          <iframe
            src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d204593.23865723637!2d9.996645!3d36.817550!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x12fd337f5e7ef543%3A0xd671924e714a0275!2sTunis%2C%20Tunisia!5e0!3m2!1sen!2stn!4v1699000000000!5m2!1sen!2stn"
            width="100%"
            height="400"
            style={{ border: 0, display: 'block' }}
            allowFullScreen
            loading="lazy"
            referrerPolicy="no-referrer-when-downgrade"
          ></iframe>
        </div>
      </section>

      {/* Section 5 - FAQ Strip */}
      <section style={{ backgroundColor: '#F9F9F7', paddingTop: '60px', paddingBottom: '60px' }}>
        <div className="max-w-[1280px] mx-auto px-6">
          <h2
            style={{
              fontFamily: 'Montserrat, sans-serif',
              fontSize: '32px',
              fontWeight: '700',
              color: '#333333',
              textAlign: 'center',
              marginBottom: '40px',
            }}
          >
            {t('contact.page.faq.title')}
          </h2>

          <div style={{ maxWidth: '800px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '12px' }}>
            {faqs.map((faq, index) => (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 10 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ duration: 0.4, ease: 'easeOut', delay: index * 0.1 }}
                style={{
                  backgroundColor: 'white',
                  border: '1px solid #E5E7EB',
                  borderRadius: '8px',
                  padding: '20px',
                }}
              >
                <div
                  onClick={() => toggleAccordion(index)}
                  style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    cursor: 'pointer',
                  }}
                >
                  <div
                    style={{
                      fontFamily: 'Inter, sans-serif',
                      fontSize: '15px',
                      fontWeight: '600',
                      color: activeAccordion === index ? '#2D472C' : '#333333',
                      transition: 'color 0.2s ease-out',
                    }}
                  >
                    {faq.question}
                  </div>
                  {activeAccordion === index ? (
                    <ChevronUp size={20} style={{ color: '#2D472C', flexShrink: 0 }} />
                  ) : (
                    <ChevronDown size={20} style={{ color: '#6B7280', flexShrink: 0 }} />
                  )}
                </div>
                {activeAccordion === index && (
                  <motion.div
                    initial={{ height: 0, opacity: 0 }}
                    animate={{ height: 'auto', opacity: 1 }}
                    exit={{ height: 0, opacity: 0 }}
                    transition={{ duration: 0.3, ease: 'easeOut' }}
                    style={{
                      overflow: 'hidden',
                      paddingTop: '12px',
                      fontSize: '14px',
                      color: '#6B7280',
                      lineHeight: '1.6',
                    }}
                  >
                    {faq.answer}
                  </motion.div>
                )}
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      <Footer />
    </div>
  );
}

import { useState } from 'react';
import { motion } from 'motion/react';
import { Navbar } from '../components/Navbar';
import { Footer } from '../components/Footer';
import { Calendar, MessageSquare, Headphones, MapPin, Mail, Phone, Clock, CheckCircle, ChevronDown, ChevronUp, Linkedin, Facebook, Instagram } from 'lucide-react';
import { Link } from 'react-router';
import { apiPost } from '../lib/api';
import c1Image from '../../assets/c1.png';
import './Contact.css';
import { useTranslation } from 'react-i18next';

export default function Contact() {
  const { t } = useTranslation();
  const [scrolled, setScrolled] = useState(false);
  const [formSubmitted, setFormSubmitted] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    subject: '',
    message: '',
  });
  const [activeAccordion, setActiveAccordion] = useState<number | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitError(null);
    setIsSubmitting(true);

    try {
      const payload = {
        name: `${formData.firstName} ${formData.lastName}`.trim(),
        email: formData.email,
        phone: formData.phone,
        subject: formData.subject,
        message: formData.message,
      };

      await apiPost('/api/contact/submit', payload);

      setFormSubmitted(true);
      setFormData({
        firstName: '',
        lastName: '',
        email: '',
        phone: '',
        subject: '',
        message: '',
      });
    } catch (err: any) {
      setSubmitError(err?.message ?? "Erreur lors de l'envoi du message.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleInputChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>
  ) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const toggleAccordion = (index: number) => {
    setActiveAccordion(activeAccordion === index ? null : index);
  };

  const faqs = [
    {
      question: t('contact.page.faq.items.0.q'),
      answer: t('contact.page.faq.items.0.a'),
    },
    {
      question: t('contact.page.faq.items.1.q'),
      answer: t('contact.page.faq.items.1.a'),
    },
    {
      question: t('contact.page.faq.items.2.q'),
      answer: t('contact.page.faq.items.2.a'),
    },
    {
      question: t('contact.page.faq.items.3.q'),
      answer: t('contact.page.faq.items.3.a'),
    },
  ];

  return (
    <div style={{ backgroundColor: '#F9F9F7', minHeight: '100vh', fontFamily: 'Inter, sans-serif' }}>
      <Navbar scrolled={scrolled} />

      {/* Section 1 - Hero */}
      <section style={{ backgroundColor: 'white', paddingTop: '100px', paddingBottom: '100px', position: 'relative', overflow: 'hidden' }}>
        {/* Decorative Circle - Top Left */}
        <div
          style={{
            position: 'absolute',
            top: '-285px',
            left: '-285px',
            width: '380px',
            height: '380px',
            borderRadius: '50%',
            backgroundColor: 'rgba(45, 71, 44, 0.06)',
            pointerEvents: 'none',
          }}
        />

        {/* Decorative Circle - Bottom Right */}
        <div
          style={{
            position: 'absolute',
            bottom: '-240px',
            right: '-240px',
            width: '320px',
            height: '320px',
            borderRadius: '50%',
            backgroundColor: 'rgba(45, 71, 44, 0.06)',
            pointerEvents: 'none',
          }}
        />

        <div className="max-w-[1280px] mx-auto px-6 relative z-10">
          <div className="grid lg:grid-cols-[45%_55%] gap-16 items-center">
            {/* Left side - Text */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, ease: 'easeOut' }}
            >
              <h1
                style={{
                  fontFamily: 'Montserrat, sans-serif',
                  fontSize: '44px',
                  fontWeight: '700',
                  color: '#333333',
                  lineHeight: '1.1',
                  maxWidth: '440px',
                  marginBottom: '20px',
                }}
              >
                {t('contact.page.heroTitle')}
              </h1>
              <p
                style={{
                  fontSize: '15px',
                  color: '#6B7280',
                  lineHeight: '1.7',
                  maxWidth: '420px',
                }}
              >
                {t('contact.page.heroSubtitle')}
              </p>
            </motion.div>

            {/* Right side - Image */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, ease: 'easeOut', delay: 0.2 }}
              className="contact-hero-media"
            >
              <img src={c1Image} alt={t('contact.hero.imageAlt')} className="contact-hero-media__img" />
              <div className="contact-hero-media__overlay" />
              <div className="contact-hero-media__badges">
                <span className="contact-hero-media__badgePrimary">{t('contact.hero.badgePrimary')}</span>
                <span className="contact-hero-media__badgeSecondary">{t('contact.hero.badgeSecondary')}</span>
              </div>
            </motion.div>
          </div>
        </div>
      </section>

      {/* Section 2 - 3 Contact Cards */}
      <section style={{ backgroundColor: 'white', paddingTop: '60px', paddingBottom: '60px' }}>
        <div className="max-w-[1280px] mx-auto px-6">
          <div className="grid md:grid-cols-3 gap-6">
            {/* Card 1 - Book a demo */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.4, ease: 'easeOut' }}
              className="transition-all duration-200"
              style={{
                backgroundColor: 'white',
                border: '1px solid #E5E7EB',
                borderRadius: '16px',
                padding: '32px',
                textAlign: 'center',
              }}
              onMouseEnter={(e) => (e.currentTarget.style.borderColor = '#2D472C')}
              onMouseLeave={(e) => (e.currentTarget.style.borderColor = '#E5E7EB')}
            >
              <Calendar size={36} style={{ color: '#C5A059', margin: '0 auto 16px' }} />
              <h3
                style={{
                  fontFamily: 'Montserrat, sans-serif',
                  fontSize: '18px',
                  fontWeight: '600',
                  color: '#333333',
                  marginBottom: '12px',
                }}
              >
                {t('contact.page.cards.demo.title')}
              </h3>
              <p style={{ fontSize: '14px', color: '#6B7280', lineHeight: '1.6', marginBottom: '20px' }}>
                {t('contact.page.cards.demo.description')}
              </p>
              <Link to="/book-demo">
                <button
                  className="transition-all duration-200 hover:opacity-90"
                  style={{
                    width: '100%',
                    height: '40px',
                    backgroundColor: '#2D472C',
                    color: 'white',
                    borderRadius: '4px',
                    border: 'none',
                    fontSize: '14px',
