                                borderRadius: '2px'
                              }}
                            ></div>
                          ))}
                        </div>
                      ) : (
                        // Regular rows for Finance/Reports
                        [1, 2, 3].map((i) => (
                          <div
                            key={i}
                            style={{
                              height: '30px',
                              backgroundColor: '#E5E7EB',
